import React from 'react'
import './Home.css'

import { useState } from 'react';

function Home() {

  const [inputNum, setInputNum] = useState("");
  const [netBalance, setNetBalance] = useState(0);

  const addAmount = ()=>{
    setNetBalance(netBalance + Number(inputNum));
    setInputNum("");
  }

  const subtractAmount = () => {
    setNetBalance(netBalance - Number(inputNum));
    setInputNum("");
  };

  return (
    <div className='Homepage'>

        <div className='showinfo'>
          <div>Total net balance: {netBalance}</div>
          <button>Show transactions</button>
        </div>

        <div className='editinfo'>
          <div className='box'>
            <h2 className='title'>Income</h2>
            <input type="number"
            step="any"
            value={inputNum}
            onChange={(e) => setInputNum(e.target.value)}
            placeholder="Enter amount"
            />
            <button onClick={addAmount}>Add Income</button>
          </div>

          <div className='box'>
            <h2 className='title'>Expenses</h2>
            <input type="number"
            step="any"
            value={inputNum}
            onChange={(e) => setInputNum(e.target.value)}
            placeholder="Enter amount"
            />
            <button onClick={subtractAmount}>Add Expense</button>
          </div>
        </div>
    </div>
  )
}

export default Home;
